code.C:
int countNonMinimum(int a[], int n) {
    if (n == 0) return 0;

    int minimum = a[0];
    int countMin = 0;

    // Find the minimum
    for (int i = 0; i < n; i++) {
        if (a[i] < minimum) {
            minimum = a[i];
        }
    }

    // Count occurrences of minimum
    for (int i = 0; i < n; i++) {
        if (a[i] == minimum) countMin++;
    }

    return n - countMin;
}

code.Java:
class Solution {
    public int countNonMinimum(int[] nums) {
        if (nums.length == 0) return 0;

        int minimum = nums[0];
        int countMin = 0;

        // Find minimum
        for (int num : nums) {
            if (num < minimum) minimum = num;
        }

        // Count occurrences of minimum
        for (int num : nums) {
            if (num == minimum) countMin++;
        }

        return nums.length - countMin;
    }
}

