function minToMax(tests) {
    const T = parseInt(tests[0]);

    for (let t = 1; t <= T; t++) {
        const N = parseInt(tests[t * 2 - 1]);
        const A = tests[t * 2].trim().split(' ').map(Number);

        // Find the minimum value in the array
        let mini = Infinity;
        for (let i = 0; i < N; i++) {
            if (A[i] < mini) {
                mini = A[i];
            }
        }

        // Count how many elements are greater than the minimum value
        let count = 0;
        for (let i = 0; i < N; i++) {
            if (A[i] > mini) {
                count++;
            }
        }

        // Output the count for the current test case
        console.log(count);
    }
}

